// NOCTURNE PRO MAX ENGINE
class StateStore {
    constructor() {
        this.state = { isPlaying: false, speed: 1.0, currentTrackIndex: 0 };
        this.listeners = [];
    }
    dispatch(update) { this.state = {...this.state, ...update}; this.listeners.forEach(cb => cb(this.state)); }
    subscribe(cb) { this.listeners.push(cb); }
    getState() { return this.state; }
}
const store = new StateStore();

// UI Elements
const DOM = {
    playBtn: document.getElementById('btn-play'),
    speedSlider: document.getElementById('speed-slider'),
    speedBtn: document.getElementById('btn-speed'),
    art: document.getElementById('current-art'),
    player: document.getElementById('dynamic-island-player')
};

// Vanta.js Background setup
if(window.VANTA) {
    VANTA.WAVES({
        el: "#vanta-bg",
        mouseControls: true, touchControls: true, gyroControls: false,
        minHeight: 200.00, minWidth: 200.00,
        scale: 1.00, scaleMobile: 1.00,
        color: 0x000000, shininess: 35.00, waveHeight: 15.00, waveSpeed: 0.75, zoom: 0.65
    });
}

// YT Engine
let ytPlayer;
function onYouTubeIframeAPIReady() {
    ytPlayer = new YT.Player('yt-player-container', {
        height: '0', width: '0', videoId: 'jfKfPfyJRdk',
        events: { 'onStateChange': e => {
            if(e.data === YT.PlayerState.PLAYING) store.dispatch({isPlaying: true});
            else store.dispatch({isPlaying: false});
        }}
    });
}
const tag = document.createElement('script');
tag.src = "https://www.youtube.com/iframe_api";
document.head.appendChild(tag);

// Controls
DOM.playBtn.onclick = () => {
    const s = store.getState();
    if(s.isPlaying) { ytPlayer?.pauseVideo(); store.dispatch({isPlaying: false}); }
    else { ytPlayer?.playVideo(); store.dispatch({isPlaying: true}); }
};

DOM.speedSlider.oninput = e => {
    const s = parseFloat(e.target.value);
    store.dispatch({speed: s});
    if(ytPlayer?.setPlaybackRate) ytPlayer.setPlaybackRate(s);
};

// Store Listener
store.subscribe(state => {
    DOM.playBtn.innerText = state.isPlaying ? '⏸' : '▶';
    DOM.speedBtn.innerText = state.speed.toFixed(1) + 'x';
});

// Magnetic Buttons
document.querySelectorAll('.magnetic-btn').forEach(btn => {
    btn.addEventListener('mousemove', e => {
        const rect = btn.getBoundingClientRect();
        const x = e.clientX - rect.left - rect.width/2;
        const y = e.clientY - rect.top - rect.height/2;
        gsap.to(btn, { x: x*0.4, y: y*0.4, duration: 0.3, ease: 'power2.out' });
    });
    btn.addEventListener('mouseleave', () => {
        gsap.to(btn, { x: 0, y: 0, duration: 0.5, ease: 'elastic.out(1, 0.3)' });
    });
});

// Audio Reactive Simulation
let audioCtx, analyser;
function simulateAudioReactivity() {
    if(store.getState().isPlaying) {
        const fakeBass = 1 + (Math.random() * 0.03);
        document.documentElement.style.setProperty('--bass-scale', fakeBass);
    } else {
        document.documentElement.style.setProperty('--bass-scale', 1);
    }
    requestAnimationFrame(simulateAudioReactivity);
}
simulateAudioReactivity();

